  (function() {
    const dbData = get_vm_cached.data || [];
    const uniqueFolders = [...new Set(dbData.map(row => row.folder_name))];

    const formattedFolders = uniqueFolders.map(folderName => {
      const vmsInFolder = dbData.filter(vm => vm.folder_name === folderName);

      const mappedVms = vmsInFolder.map(vm => {
        let statusIcon = '🔴'; 
        if (vm.power_state === 'poweredOn') statusIcon = '🟢';
        else if (vm.power_state === 'provisioning') statusIcon = '🟡';

        return { 
          id: vm.vm_moid, 
          name: vm.vm_name, 
          statusIcon: statusIcon 
        };
      });

      return { name: folderName, vms: mappedVms };
    });

    // The widget receives this as appsmith.model.folders
    return { folders: formattedFolders };
  })()
}}

