.vcenter-sidebar {
  font-family: system-ui, -apple-system, sans-serif;
  padding: 10px;
  background: #ffffff;
  /* Change height to fill the Appsmith widget box */
  height: 100%;
  /* Enable scrolling inside the widget if the list is long */
  overflow-y: auto;
  /* Hide horizontal scroll if folder names are long */
  overflow-x: hidden;
}

.folder-group {
  margin-bottom: 8px;
}

.folder-name {
  font-weight: 600;
  cursor: pointer;
  padding: 6px;
  user-select: none;
  border-radius: 4px;
}

.folder-name:hover {
  background-color: #f3f4f6;
}

.vm-list {
  list-style-type: none;
  padding-left: 24px;
  margin-top: 4px;
  margin-bottom: 0;
}

.vm-item {
  padding: 6px;
  font-size: 14px;
  cursor: pointer;
  border-radius: 4px;
  color: #374151;
}

.vm-item:hover {
  background-color: #e5e7eb;
  color: #9941ec; /* Your primary purple color */
}

