import React, { useState, useEffect } from "https://esm.sh/react@18.2.0";
import ReactDOM from "https://esm.sh/react-dom@18.2.0";

function SidebarTree() {
  const [folders, setFolders] = useState(appsmith.model.folders || []);

  useEffect(() => {
    // This makes the widget react dynamically to get_vm_cached updates
    const handleModelChange = (newModel) => {
      if (newModel && newModel.folders) {
        setFolders(newModel.folders);
      }
    };
    appsmith.onModelChange(handleModelChange);
  }, []);

  return (
    <div className="vcenter-sidebar">
      {folders.map(folder => (
        <details key={folder.name} className="folder-group">
          <summary className="folder-name">📁 {folder.name}</summary>
          <ul className="vm-list">
            {folder.vms.map(vm => (
              <li 
                key={vm.id} 
                className="vm-item"
                onClick={() => {
  // 1. Force the ID into the widget's model
  appsmith.updateModel({ selectedId: vm.id });

  // 2. Trigger the event signal
  appsmith.triggerEvent("onVmClick");
}}
              >
                {vm.statusIcon} {vm.name}
              </li>
            ))}
          </ul>
        </details>
      ))}
    </div>
  );
}

appsmith.onReady(() => {
  ReactDOM.render(<SidebarTree />, document.getElementById("root"));
});
